  actionId: "cargo"
  args: "audit"
}

node[action: "Node audit"] {
  adapter: "shell"
  actionId: "pnpm"
  args: "audit --prod"
}

merge[cloud_ai: "Merge findings"] {
  provider: "claude"
  modelId: "claude-opus-4-5"
  prompt: "Merge these advisories into a single CVE list."
}

rust --> merge
node --> merge

flow "zowe-fanin" v1

a[action: "Probe A"] {
  adapter: "zowe"
  actionId: "cli-raw"
  command: "jobs list"
}

b[action: "Probe B"] {
  adapter: "zowe"
  actionId: "cli-raw"
  command: "files list ds"
}

merge[action: "Merge"] {
  adapter: "shell"
  actionId: "run-command"
  command: "cat /tmp/a.json /tmp/b.json > /tmp/c.json"
}

a --> merge
b --> merge

flow "test-triage" v1

test[action: "Test"] {
  adapter: "shell"
  actionId: "cargo"
  args: "test --workspace"
}

triage[cloud_ai: "Triage"] {
  provider: "claude"
  modelId: "claude-opus-4-5"
  prompt: "Summarise the failure in two sentences."
}

test.fail --> triage

flow "always-and-fail" v1

build[action: "Build"] {
  adapter: "shell"
  actionId: "pnpm"
  args: "build"
}

deploy[action: "Deploy"] {
  adapter: "shell"
  actionId: "kubectl"
  args: "rollout restart deploy/api"
}

notify[action: "Notify"] {
  adapter: "shell"
  actionId: "curl"
  args: "-fsS -X POST https://hooks.example.com/slack"
}

build.pass --> deploy
build.fail --> notify

flow "build-then-notes" v1

build[action: "Build"] {
  adapter: "shell"
  actionId: "pnpm"
  args: "build"
}

notes[cloud_ai: "Notes"] {
  provider: "claude"
  modelId: "claude-opus-4-5"
  prompt: "Draft a release note."
}

build.pass --> notes

flow "submit-interpret" v1

submit[action: "Submit"] {
  adapter: "zowe"
  actionId: "cli-raw"
  command: "jobs submit local-file"
  connectionId: "lpar-test"
}

interpret[ai: "Interpret"] {
  task: "spool_interpretation"
  modelId: "spool-interpreter"
}

submit.fail --> interpret

flow "test-log-triage" v1

test[action: "Test"] {
  adapter: "shell"
  actionId: "cargo"
  args: "test --workspace"
}

log[utility: "Log"] {
  actionId: "log"
  level: "warn"
}

triage[cloud_ai: "Triage"] {
  provider: "claude"
  modelId: "claude-opus-4-5"
  prompt: "Summarise the test failure."
}

test.fail --> log
log --> triage

flow "zowe-archive-cool" v1

list[action: "List jobs"] {
  adapter: "zowe"
  actionId: "cli-raw"
  command: "jobs list"
}

archive[action: "Archive"] {
  adapter: "shell"
  actionId: "run-command"
  command: "tar -czf /tmp/jobs.tgz /tmp/jobs.json"
}

cool[utility: "Cool"] {
  actionId: "sleep"
  durationMs: 2000
}

list --> archive
archive --> cool

flow "interpret-then-fix" v1

interpret[ai: "Interpret"] {
  task: "spool_interpretation"
  modelId: "spool-interpreter"
}

fix[action: "Apply suggested fix"] {
  adapter: "shell"
  actionId: "run-command"
  command: "true"
}

interpret.pass --> fix

flow "cloud-log-exit" v1

draft[cloud_ai: "Draft"] {
  provider: "openai"
  modelId: "gpt-5"
  prompt: "Pick a yes or no."
}

note[utility: "Note"] {
  actionId: "log"
  level: "info"
}

done[action: "Done"] {
  adapter: "shell"
  actionId: "run-command"
  command: "echo done"
}

draft --> note
note --> done

flow "tri-adapter" v1

ping[action: "Healthcheck"] {
  adapter: "shell"
  actionId: "curl"
  args: "-fsS https://example.com/health"
}

list[action: "List jobs"] {
  adapter: "zowe"
  actionId: "cli-raw"
  command: "jobs list"
  connectionId: "lpar-test"
}

summary[cloud_ai: "Summary"] {
  provider: "claude"
  modelId: "claude-opus-4-5"
  prompt: "Summarise both outputs."
}

ping.pass --> list
list.pass --> summary

flow "fork-shell-ai-util" v1

seed[action: "Seed"] {
  adapter: "shell"
  actionId: "run-command"
  command: "echo seed"
}

explain[ai: "Explain"] {
  task: "spool_interpretation"
  modelId: "spool-interpreter"
}

done[utility: "Done"] {
  actionId: "log"
  level: "info"
}

seed --> explain
seed --> done

flow "deploy-verify-rollback-alert" v1

deploy[action: "Deploy"] {
  adapter: "shell"
  actionId: "kubectl"
  args: "rollout restart deploy/api"
}

verify[action: "Verify"] {
  adapter: "shell"
  actionId: "curl"
  args: "-fsS https://example.com/health"
}

rollback[action: "Rollback"] {
  adapter: "shell"
  actionId: "kubectl"
  args: "rollout undo deploy/api"
}

alert[action: "Alert"] {
  adapter: "shell"
  actionId: "curl"
  args: "-fsS -X POST https://hooks.example.com/pagerduty"
}

deploy --> verify
verify.fail --> rollback
rollback --> alert

flow "branch-converge" v1

decide[utility: "Decide"] {
  actionId: "branch"
  on: "payload.status"
}

a[action: "Path A"] {
  adapter: "shell"
  actionId: "run-command"
  command: "echo a"
}

b[action: "Path B"] {
  adapter: "shell"
  actionId: "run-command"
  command: "echo b"
}

done[action: "Done"] {
  adapter: "shell"
  actionId: "run-command"
  command: "echo done"
}

decide.pass --> a
decide.fail --> b
a --> done
b --> done

